#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int ans = 0;
    for (int i = 0; i < 10; i++) {
        int cnt[2] = {0, 0};
        for (int j = 0; j < n; j++) {
            cnt[(a[j] >> i) & 1]++;
        }
        ans += (cnt[0] < cnt[1] ? cnt[0] : cnt[1]);
    }
    printf("%d\n", ans);
    return 0;
}

