code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }
        int ans = 0;
        for (int i = 0; i < 10; i++) {
            int cnt0 = 0, cnt1 = 0;
            for (int j = 0; j < n; j++) {
                if (((a[j] >> i) & 1) == 0) cnt0++;
                else cnt1++;
            }
            ans += Math.min(cnt0, cnt1);
        }
        System.out.println(ans);
    }
}

