const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        let ans = 0;
        for (let i = 0; i < 10; i++) {
            let cnt = [0, 0];
            for (let j = 0; j < n; j++) {
                cnt[(a[j] >> i) & 1]++;
            }
            ans += Math.min(...cnt);
        }
        console.log(ans);
        rl.close();
    }
});

